const VERTEX_SHADER = `
attribute vec3 aPosition;
attribute vec3 aNormal;

uniform float uYaw;
uniform float uPitch;
uniform float uDistance;
uniform float uAspect;
uniform float uScale;

varying vec3 vNormal;
varying vec3 vLocalNormal;
varying vec3 vViewPosition;
varying vec3 vLocal;
varying float vOrientation;

vec3 rotateView(vec3 point) {
  float cy = cos(uYaw);
  float sy = sin(uYaw);
  float cp = cos(uPitch);
  float sp = sin(uPitch);
  float x1 = cy * point.x + sy * point.z;
  float z1 = -sy * point.x + cy * point.z;
  return vec3(x1, cp * point.y - sp * z1, sp * point.y + cp * z1);
}

void main() {
  vec3 local = aPosition * uScale;
  vec3 viewPosition = rotateView(local);
  viewPosition.z -= uDistance;

  float nearPlane = 0.1;
  float farPlane = 40.0;
  float focal = 2.65;
  float clipZ = ((farPlane + nearPlane) / (nearPlane - farPlane)) * viewPosition.z
    + ((2.0 * farPlane * nearPlane) / (nearPlane - farPlane));

  gl_Position = vec4(
    (focal / uAspect) * viewPosition.x,
    focal * viewPosition.y,
    clipZ,
    -viewPosition.z
  );

  vNormal = rotateView(aNormal);
  vLocalNormal = aNormal;
  vViewPosition = viewPosition;
  vLocal = local;
  vOrientation = dot(aNormal, aPosition);
}
`;

